(** Pops of tabulated caller frames of the analyzed network. *)
let last_passive_pops : int ref = ref 0

let dummy_aux : A.handle -> string -> A.kidx -> D.t list -> D.t option =
 fun _ _ _ _ -> None

let step (h : A.handle) (sigma : A.state) ((phi, k) : A.Key.t) (rho : A.aenv)
    (kont : A.kont) : A.succ list =
  let l = Retargeting.Partition.lab phi in
  if l = 91 then List.rev (seg_init dummy_aux h k kont rho)
  else if l = 4 then List.rev (head_l4 dummy_aux h k kont rho)
  else if l = 9 then List.rev (head_l9 dummy_aux h k kont rho)
  else if l = 12 then List.rev (head_l12 dummy_aux h k kont rho)
  else if l = 84 then List.rev (head_l84 dummy_aux h k kont rho)
  else if l = 0 || l = 1 || l = 5 || l = 6 || l = 11 || l = 13 || l = 15 || l = 17 || l = 21 || l = 25 || l = 29 || l = 33 || l = 37 || l = 41 || l = 46 || l = 54 || l = 65 || l = 78 || l = 80 || l = 86 then return_all dummy_aux h sigma phi k rho kont
  else if l = 2 || l = 7 || l = 16 || l = 19 || l = 20 || l = 23 || l = 24 || l = 27 || l = 28 || l = 31 || l = 32 || l = 35 || l = 36 || l = 39 || l = 40 || l = 42 || l = 43 || l = 44 || l = 47 || l = 48 || l = 51 || l = 52 || l = 55 || l = 56 || l = 58 || l = 61 || l = 62 || l = 63 || l = 66 || l = 67 || l = 69 || l = 71 || l = 74 || l = 75 || l = 76 || l = 77 || l = 79 || l = 81 || l = 83 || l = 87 || l = 88 then begin incr last_passive_pops; [] end
  else []

(** The stored analysis with the auxiliary summary inlined and analyzed. *)
let analyze_t ?(arg : D.t = D.int_lit 0) (p : Retargeting.T_encoding.program) :
    A.analysis =
  A.analyze_t_with ~step ~arg p

