let heads_f : Retargeting.Label.Set.t =
  Retargeting.Label.Set.of_list [ 91; 4; 9; 12; 84 ]

let step_f (leak : bool) (h : A.handle) (sigma : A.state)
    ((phi, k) : A.Key.t) (rho : A.aenv) (kont : A.kont) : A.succ list =
  let l = Retargeting.Partition.lab phi in
  if l = 91 then List.rev (fseg_init dummy_aux leak h k kont phi rho)
  else if l = 4 then List.rev (fhead_l4 dummy_aux leak h k kont phi rho)
  else if l = 9 then List.rev (fhead_l9 dummy_aux leak h k kont phi rho)
  else if l = 12 then List.rev (fhead_l12 dummy_aux leak h k kont phi rho)
  else if l = 84 then List.rev (fhead_l84 dummy_aux leak h k kont phi rho)
  else if l = 0 || l = 1 || l = 5 || l = 6 || l = 11 || l = 13 || l = 15 || l = 17 || l = 21 || l = 25 || l = 29 || l = 33 || l = 37 || l = 41 || l = 46 || l = 54 || l = 65 || l = 78 || l = 80 || l = 86 then freturn_all dummy_aux leak h sigma phi k rho kont
  else begin incr last_passive_pops; [] end

(** The stored specialized (cut-limited) analysis with the auxiliary summary analyzed.
    [~exact:true] is the designated instance (the stored summary gate). *)
let analyze_t_fminus ?(arg : D.t = D.int_lit 0) ?(exact = false)
    (p : Retargeting.T_encoding.program) : A.analysis =
  A.analyze_t_with
    ~step:(step_f false)
    ~passive:(Retargeting.Calc_pe.faithful_passive heads_f)
    ~exact ~arg p

(** The stored paper-faithful analysis with the auxiliary summary analyzed. *)
let analyze_t_faithful ?(arg : D.t = D.int_lit 0) ?(exact = false)
    (p : Retargeting.T_encoding.program) : A.analysis =
  A.analyze_t_with
    ~step:(step_f true)
    ~passive:(Retargeting.Calc_pe.faithful_passive heads_f)
    ~exact ~arg p

end
end

